# ---------------------------------------------------------------------------
# Greeting
# ---------------------------------------------------------------------------

class TestGreeting:
    """Tests for the Greeting dataclass."""

    def test_greeting_stores_fields(self) -> None:
        g = Greeting("World", "Hello")
        assert g.recipient == "World"
        assert g.message == "Hello"

    def test_greeting_formatted_contains_recipient_and_message(self) -> None:
        g = Greeting("Alice", "Hi")
        result = g.formatted()
        assert "Alice" in result, "formatted output should contain recipient"
        assert "Hi" in result, "formatted output should contain message"

    def test_greeting_rejects_blank_recipient(self) -> None:
        with pytest.raises((ValueError, TypeError)):
            Greeting("", "Hello")

    def test_greeting_rejects_blank_message(self) -> None:
        with pytest.raises((ValueError, TypeError)):
            Greeting("World", "   ")


# ---------------------------------------------------------------------------
# TimeOfDay
# ---------------------------------------------------------------------------

class TestTimeOfDay:
    """Tests for TimeOfDay.of()."""

    def test_morning_for_hour_less_than_12(self) -> None:
        assert TimeOfDay.of(0) is TimeOfDay.MORNING
        assert TimeOfDay.of(11) is TimeOfDay.MORNING

    def test_afternoon_for_hour_12_to_16(self) -> None:
        assert TimeOfDay.of(12) is TimeOfDay.AFTERNOON
        assert TimeOfDay.of(16) is TimeOfDay.AFTERNOON

    def test_evening_for_hour_17_and_above(self) -> None:
        assert TimeOfDay.of(17) is TimeOfDay.EVENING
        assert TimeOfDay.of(23) is TimeOfDay.EVENING


